var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"서면을 주고받긴 했지만, 실제로 뵙는 건 처음이군요. 시스터.","JPN":"書面は交わしましたが、実際会うのは初めてですね。シスター。","ENG":"Though we have exchanged letters before, I believe this is the first time we meet in person, Sister.","TWN":"雖然彼此有書信往來，但這還是第一次見到本人呢，姊妹。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"비블리데 루체 자매님이시군요.","JPN":"シスター・ビブリデ・ルーチェですね。","ENG":"It's you, Sister Biblide Luce.","TWN":"原來是布莉黛·露契姊妹。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……감사합니다. 자매님.","JPN":"……ありがとうございます、シスター・ルーチェ。","ENG":"Thank you, Sister...","TWN":"……謝謝你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매님이 손 써주시지 않았다면, 루퍼 자매님에 대한 종교 재판이 벌어졌을 거예요.","JPN":"あなたが手を尽くしてくれなかったら、シスター・ルーパーへの宗教裁判が始まっていたことでしょう。","ENG":"If it wasn’t for you, the Inquisition would have sided against Sister Looper.","TWN":"要不是你出手，洛珀姊妹很可能會受到宗教裁判。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그리고 헤밍턴 형제님의 일도 감사드려요.","JPN":"そしてハミントン兄弟のことも感謝しますわ。","ENG":"And please thank Brother Hammington for me.","TWN":"海明頓弟兄的事也很謝謝你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루체 자매님이 없었다면, 그 분은…….","JPN":"シスター・ルーチェがいなかったら、あの方は……","ENG":"If you weren't there to help... he...","TWN":"要不是你，他……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 정정해드리죠, 시스터 넬슨.","JPN":"喜んで訂正いたします、シスターネルソン。","ENG":"I would be more than happy to rephrase, Sister Nelson.","TWN":"我要更正一下，尼爾森姊妹。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저는 제 목적을 위해 성무 SI3E를 조사하고 있을 뿐입니다.","JPN":"私は自分の目的のために聖務SI3Eを調査しているだけです。","ENG":"I was reading Sacred Mission SI3E for personal reasons.","TWN":"我調查聖務SI3E有我私人的原因，"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"딱히 감사 인사를 받을 이유는 없죠.","JPN":"とりたてて感謝される理由はありません。","ENG":"There is no need to thank me.","TWN":"所以沒理由接受你的道謝。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그럼, 최소한 자매님의 질문에 성실히 답하는 것이 그 감사의 표시가 되겠네요.","JPN":"でしたら、あなたの質問に真面目に答えることがせめてもの感謝のしるしになるでしょう。","ENG":"Then, I believe answering your questions truthfully will be the least I can do as a thanks for what you did for us.","TWN":"那至少讓我誠實地回答你的問題，以示感謝吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"좋습니다. 제가 열람한 참고인 중에 가장 협조적이시군요.","JPN":"ありがとうございます。私が閲覧した参考人の中でもっとも協力的ですね。","ENG":"Very well. Among the witnesses I have browsed you are the most cooperative one.","TWN":"好，你是我讀過的證人中最配合的呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아시다시피 베네딕트 콘스탄틴은 성무 SI3E를 계기로 완전히 변절했습니다.","JPN":"ご存じでしょうが、ベネディクト・コンスタンティンは聖務SI3Eをきっかけに完全に宗旨替えをしてしまいました。","ENG":"As you may be aware, Benedict Constantine has fully  changed sides after Sacred Mission SI3E.","TWN":"你應該知道，本尼迪克特·康斯坦丁藉著聖務SI3E叛變一事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대략적인 정황은 읽어냈지만 여전히 의문이 남아있죠.","JPN":"大体の状況は読めましたが、依然として疑問が残っています。","ENG":"I read the rough outline, but there are still some questions that need to be answered.","TWN":"雖然我已經讀出一個脈絡，但還是有些疑問。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"하지만 괜찮을까요?","JPN":"でも大丈夫でしょうか？","ENG":"Are you sure this will be all right?","TWN":"可是沒關係嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루퍼 자매님께 구조되기 전까지 저는 신부님의 행동을…….","JPN":"シスター・ルーパーが救助されるまで、私は神父様の行動を……","ENG":"Until I was rescued by Sister Looper...","TWN":"在洛珀姊妹把我救出來之前，我對神父的下落……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"결론을 읽어내는 건 접니다. 그건 당신이 걱정할 문제가 아니죠.","JPN":"結論を読み取るのは私です。それはあなたが心配する問題ではありません。","ENG":"You have nothing to be concerned about. I will be the one who reads the end.","TWN":"結論是由我來讀的，不需要你費心。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"좋아요, 자매님.","JPN":"わかりました、シスター・ルーチェ。","ENG":"Okay, Sister.","TWN":"好的，姊妹。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"정신을 차린 곳은 몹시 어둡고……","JPN":"目を覚ますと、そこはとても暗く……","ENG":"When I woke up, it was pitch black, and...","TWN":"我清醒的地方非常黑……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"여긴…… 어디지?","JPN":"ここは……どこ？","ENG":"Where... am I?","TWN":"這是……哪裡？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"윽, 머리가……! 다른 대원분들은……?","JPN":"うっ、頭が……！　他の隊員は……？","ENG":"Ugh! My head...! Where are the others...?","TWN":"唔，我的頭……！其他人呢……？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"안쪽에서 물소리가 들리는 걸 보면…… 동굴 같은 곳인가?","JPN":"奥から水の音が聞こえるわ……ここは洞窟なのかしら？","ENG":"I can hear water coming from inside... Is this a cave?","TWN":"裡面好像有水聲……我在洞穴裡嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아니면 어딘가의 지하실일지도 모르겠어.","JPN":"もしかしたら、どこかの地下室かもしれないわ。","ENG":"Or it could be a basement somewhere...","TWN":"還是某個地下室？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"벽의 구조를 만져보면…….","JPN":"壁に触って構造を把握すれば……","ENG":"If I touch the wall...","TWN":"牆壁的結構摸起來……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"살려……","JPN":"助けて……","ENG":"Please...","TWN":"救命……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"살려주세요…… 수녀님.","JPN":"助けてください……シスター。","ENG":"Save me... Sister...","TWN":"救我……修女。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"여, 여기 나 말고도 사람이……?","JPN":"こ、ここに私以外にも人が……？","ENG":"Th-there's someone else here except me...?","TWN":"這裡除了我還有別人……？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"살려주세요…….","JPN":"助けてください……","ENG":"Save me...","TWN":"救我……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"자매님, 정신 차려 보세요! 자매님!","JPN":"シスター、しっかりしてください！　シスター！","ENG":"Sister, wake up! Sister!","TWN":"姊妹，你醒醒！姊妹！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"좋아. 일시적으로 기운을 차리게 하는 정도라면…….","JPN":"一時的に気力を回復させるくらいなら……","ENG":"Good. My abilities will be enough...","TWN":"好吧，只是要讓她暫時清醒過來的話……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"어, 어째서?","JPN":"ど、どうして？","ENG":"H-huh...?","TWN":"為…為什麼？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"이, 이럴 수가……? 어째서 내 기도가 닿지 않는 거지?","JPN":"そ、そんな……？　どうして私の祈りが届かないの？","ENG":"H-how could this...? Why aren't my prayers working?","TWN":"怎…怎麼會……？我的祈禱為何沒有發揮作用？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"힘을…… 사용할 수가 없어.","JPN":"力が……使えない。","ENG":"I can't... use my power.","TWN":"我沒辦法……使用能力。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이상한 대목이로군요, 시스터.","JPN":"おかしな一節ですね、シスター。","ENG":"What a strange occurrence, Sister.","TWN":"姊妹，這段有點奇怪。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"워치의 계수기가 0을 가리켜, 아예 그림자로 전락한다면 모를까…….","JPN":"ウォッチの計測器が0を示し、完全にシャドウと化したならともかく……","ENG":"It would make sense if your Watch fell to zero and you became a Shadow...","TWN":"能量環的計數指向0，要是淪落成暗影還有可能……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"한 번 발현된 카운터의 능력이 갑자기 사라지는 경우는 결단코 없습니다.","JPN":"一度発現したカウンター能力がいきなり消えるということは決してありません。","ENG":"But there has never been an instance of a Counter ability suddenly disappearing once it has been realized.","TWN":"但制裁者的能力一旦展現後，是不可能突然消失的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"의무관들이 당신의 몸 상태를 조사해봤지만, 아직 원인을 밝혀내지 못했다고 하던데…….","JPN":"医務官があなたの身体の状態を調べて、いまだ原因が掴めていないとのことでしたが……","ENG":"The medics have examined your condition but were unable to determine the cause...","TWN":"醫務官有檢查過你的身體狀態，不過似乎還沒找到原因……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"본인이 느끼기에는 어떤가요?","JPN":"あなたはどうですか？","ENG":"How about you? Do you feel different?","TWN":"你自己感覺如何？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"지금도 제 워치는 정상적으로 움직이고 있어요.","JPN":"今も私のウォッチはちゃんと動いていますわ。","ENG":"My Watch is still working normally.","TWN":"我的能量環現在還在正常運作中。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"예전처럼…… 기도할 수 없게 된 것뿐이죠.","JPN":"以前のような……祈りができなくなっただけです。","ENG":"But I just can't... pray like I used to.","TWN":"只是像之前一樣……無法祈禱。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시간이 지나면 괜찮아질 것 같다는 말씀이신가요?","JPN":"時が経てば治りそうだということですか？","ENG":"Do you mean that it will get better over time?","TWN":"你的意思是，應該過些時間就會恢復嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That’s...","TWN":"這個……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"일단, 알겠습니다. 이번에는 생존자 아이에 대해서 묻도록 하죠.","JPN":"とりあえず、わかりました。今度は生存者である子どもについてお聞きします。","ENG":"Understood. I will move on to asking about the child that survived.","TWN":"這個部分先到這裡，接下來我要問你其他倖存者的事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"보고서에는 베네딕트가 그 아이를 구했다고 쓰여 있군요. 사실인가요?","JPN":"報告書にはベネディクトがあの子を助けたと書いてありました。本当ですか？","ENG":"According to the report, it was Benedict who saved her. Is this true?","TWN":"報告上寫說，是本尼迪克特將那孩子救出來的，這是真的嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네, 사실이에요. 나중에 신부님이 구조하셨어요.","JPN":"はい、本当です。後で神父様が救助なさいました。","ENG":"Yes, it's true. She was rescued by Priest Benedict later.","TWN":"對，是真的，是神父救她出來的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……혹시나 해서 물어보는 것입니다만.","JPN":"……もしかしてと思って聞きますが。","ENG":"This might sound like an odd question, but...","TWN":"……那我確認一下，"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신, 그 아이로부터 무언가를 가져갔나요?","JPN":"あなた、あの子から何かを取りましたか？","ENG":"Did you take anything from the child?","TWN":"你，有從那孩子身上拿走什麼東西嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네? 그게 무슨 말씀이세요?","JPN":"はい？　それはどういうことですか？","ENG":"Excuse me? I don’t understand what you mean...","TWN":"嗯？那是什麼意思？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아니요. 실언이었군요. 다음으로 넘어가죠.","JPN":"いいえ。失言でした。次に進みましょう。","ENG":"My apologies. I must have misspoken. Shall we move on?","TWN":"沒事，當我沒問，我們繼續。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신이 갇혀 있던 마을 지하수로는 내부 구조가 꽤 복잡했습니다.","JPN":"あなたが閉じこめられていた村の地下水路は、かなり複雑な内部構造をしていました。","ENG":"The underground waterway structure in which you were trapped appeared to have been quite complicated.","TWN":"你被囚禁的地下道，裡面的結構非常複雜。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"누군가의 도움 없이 혼자 탈출하기에는 역부족이었을 텐데요.","JPN":"誰かの助けなしに一人で脱出するのは難しかったはずですが。","ENG":"It would have been difficult to escape without anyone's help.","TWN":"若沒有其他人的幫助，自己是永遠不可能逃得出來的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"옳은 말씀이에요, 루체 조사관님.","JPN":"ごもっともです、ルーチェ調査官。","ENG":"That's correct, Investigator Luce.","TWN":"你說的沒錯，露契調查官。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"실은, 도움을 받았거든요.","JPN":"実は、助けてもらいました。","ENG":"I did receive help.","TWN":"我確實是有受到其他人的幫助，"},"stage":{"bg":"UNDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>성황청의 협력자</color> 분에게.","JPN":"<color=#ffd34c>聖皇庁の協力者</color>の方に。","ENG":"From the <color=#ffd34c>Holy Curia's ally</color>...","TWN":"那個人是<color=#ffd34c>聖皇廳的夥伴</color>。"},"stage":{"bg":"UNDER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGNES_VATICAN_SUPPLEMENT_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};